CREATE TRIGGER [dbo].[BillOfMaterial_History]ON [dbo].[BillOfMaterial]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.BillOfMaterialId IS NOT NULL AND d.BillOfMaterialId IS NULL THEN 'I' 		WHEN i.BillOfMaterialId IS NOT NULL AND d.BillOfMaterialId IS NOT NULL THEN 'U' 		WHEN i.BillOfMaterialId IS NULL AND d.BillOfMaterialId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.BillOfMaterialId = d.BillOfMaterialId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_BillOfMaterial([BillOfMaterialId], [Name], [Description], [PartId], [EffectiveStartDate], [EffectiveStartDateUtc], [EffectiveEndDate], [EffectiveEndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfMaterialId], [Name], [Description], [PartId], [EffectiveStartDate], [EffectiveStartDateUtc], [EffectiveEndDate], [EffectiveEndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_BillOfMaterial([BillOfMaterialId], [Name], [Description], [PartId], [EffectiveStartDate], [EffectiveStartDateUtc], [EffectiveEndDate], [EffectiveEndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfMaterialId], [Name], [Description], [PartId], [EffectiveStartDate], [EffectiveStartDateUtc], [EffectiveEndDate], [EffectiveEndDateUtc], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND